-- ============================================================================
-- 27. 시퀀스 동기화 (명시적 PK 적재 후 NEXTVAL 충돌 방지)
--     schema.sql 정의명과 매퍼 사용명을 모두 시도, 없는 시퀀스는 예외 무시
-- ============================================================================
DECLARE
    TYPE t_rec  IS RECORD (seq VARCHAR2(50), tab VARCHAR2(50), col VARCHAR2(50));
    TYPE t_list IS TABLE OF t_rec;
    l t_list := t_list(
        t_rec('SEQ_EMPLOYEE','EMPLOYEE','EMP_ID'),
        t_rec('EMPLOYEE_SEQ','EMPLOYEE','EMP_ID'),
        t_rec('SEQ_ATTENDANCE','ATTENDANCE','ATTENDANCE_ID'),
        t_rec('SEQ_PRODUCT','PRODUCT','PRODUCT_ID'),
        t_rec('SEQ_PRODUCT_SPEC','PRODUCT_SPEC','SPEC_ID'),
        t_rec('SEQ_CUSTOMER','CUSTOMER','CUSTOMER_ID'),
        t_rec('SEQ_PURCHASE_ORDER','PURCHASE_ORDER','PO_ID'),
        t_rec('SEQ_PO','PURCHASE_ORDER','PO_ID'),
        t_rec('SEQ_PURCHASE_ORDER_DETAIL','PURCHASE_ORDER_DETAIL','PO_DETAIL_ID'),
        t_rec('SEQ_PO_DETAIL','PURCHASE_ORDER_DETAIL','PO_DETAIL_ID'),
        t_rec('SEQ_RECEIVING','RECEIVING','RECEIVING_ID'),
        t_rec('SEQ_RECEIVING_DETAIL','RECEIVING_DETAIL','RECEIVING_DETAIL_ID'),
        t_rec('SEQ_RECEIVING_DTL','RECEIVING_DETAIL','RECEIVING_DETAIL_ID'),
        t_rec('SEQ_INVENTORY_LOT','INVENTORY_LOT','INVENTORY_LOT_ID'),
        t_rec('SEQ_STOCK_MOVEMENT','STOCK_MOVEMENT','MOVEMENT_ID'),
        t_rec('SEQ_EXPIRY_ALERT','EXPIRY_ALERT','ALERT_ID'),
        t_rec('SEQ_SALES_ORDER','SALES_ORDER','SO_ID'),
        t_rec('SEQ_SALES_ORDER_DETAIL','SALES_ORDER_DETAIL','SO_DETAIL_ID'),
        t_rec('SEQ_SHIPMENT','SHIPMENT','SHIPMENT_ID'),
        t_rec('SEQ_SHIPMENT_DETAIL','SHIPMENT_DETAIL','SHIPMENT_DETAIL_ID'),
        t_rec('SEQ_RETURN_REQUEST','RETURN_REQUEST','RETURN_ID'),
        t_rec('SEQ_DISPOSAL','DISPOSAL','DISPOSAL_ID'),
        t_rec('SEQ_PURCHASE_INVOICE','PURCHASE_INVOICE','PURCHASE_INVOICE_ID'),
        t_rec('SEQ_SALES_INVOICE','SALES_INVOICE','SALES_INVOICE_ID'),
        t_rec('SEQ_ACCOUNT_PAYABLE','ACCOUNT_PAYABLE','AP_ID'),
        t_rec('SEQ_ACCOUNT_RECEIVABLE','ACCOUNT_RECEIVABLE','AR_ID'),
        t_rec('SEQ_PAYMENT','PAYMENT','PAYMENT_ID'),
        t_rec('SEQ_SETTLEMENT','SETTLEMENT','SETTLEMENT_ID'),
        t_rec('SEQ_ALERT','ALERT','ALERT_ID')
    );
    v_max NUMBER;
    v_cur NUMBER;
BEGIN
    FOR i IN 1 .. l.COUNT LOOP
        BEGIN
            EXECUTE IMMEDIATE 'SELECT NVL(MAX(' || l(i).col || '), 0) FROM ' || l(i).tab INTO v_max;
            WHILE v_max > 0 LOOP
                EXECUTE IMMEDIATE 'SELECT ' || l(i).seq || '.NEXTVAL FROM DUAL' INTO v_cur;
                EXIT WHEN v_cur >= v_max;
            END LOOP;
        EXCEPTION
            WHEN OTHERS THEN NULL;
        END;
    END LOOP;
END;
/

